var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"여, 여러분, 미하~","JPN":"み、皆さん、ミハ～！","ENG":"H-hi, everyone! It's me, Miya!","TWN":"大…大家好～我是米婭～"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"오늘은…… 하트베리 멤버들이랑 다 같이 그라운드 원 번화가에 쇼핑을 나왔는데요.","JPN":"今日は……ハートベリーのみんなとグラウンド・ワンの繫華街に買い物に来ました。","ENG":"I’m now in the Ground One downtown, shopping with HRT Berry members.","TWN":"我今天……和愛心莓果的成員們一起到G1的鬧區來逛街～"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"보시는 것처럼 너무너무 더워요. 어젯밤에도 열대야 때문에 다들 잠자기 힘드셨죠?","JPN":"ご覧のとおりすっごーく暑いです。昨日も熱帯夜のせいでみんな寝苦しかったでしょう？","ENG":"As you can see, it’s super hot today. I’m sure you all suffered through the tropical night yesterday.","TWN":"天氣真的好熱喔～ 昨天晚上大家應該也都熱到睡不著吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"도시가 전부 찜통이다냥…… 온몸이 땀투성이다냥……","JPN":"都市中が熱湯風呂みたいだにゃ……全身汗だくだにゃあ……","ENG":"The whole city is bwoiling... I’m sweating all owver...","TWN":"整個城市像個烤爐一樣喵……身上都是汗喵……"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"매니저, 이런 여름엔 수영장이나 워터 파크가 방송 아이템으로 제격 아냐?","JPN":"マネージャー、こんな夏にはプールやウォーターパークで配信したほうがウケやすいんじゃない？","ENG":"Manager, don’t you think going to a swimming pool or a water park would have worked better in this weather?","TWN":"經紀人！你沒聽過一首歌嗎？每到夏天我要去海邊～～"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"튜브 위에서 줄다리기나 누구 수영복이 제일 섹시한지 투표 받거나!","JPN":"チューブの上で綱引きしたり、誰の水着が一番セクシーなのか投票したりね！","ENG":"We could have played tug of war on swim rings, or had people vote for the sexiest swimsuit.","TWN":"至少也要比個沙灘排球，或是投票看誰的泳裝最性感吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"뭐, 1등은 겨뤄 볼 것도 없이 내 차지겠지만!","JPN":"まあ、結果は見なくてもこのアタシが1位に決まっているけどね！","ENG":"I’m sure I would have won!","TWN":"雖然說沒什麼好比的，因為第一名一定是我！"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"그만둬. 거기서 더 벗으면 너무 파렴치해.","JPN":"やめたほうがいいよ。それ以上の露出は下品に見えるから。","ENG":"Stop it. You can’t take off any more clothes, shame on you.","TWN":"可以了，怕人家不知道你愛露嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"누구더러 파렴치래. 자기는 달밤에 바니걸 복장으로 뛰어다니다 해외 토픽 올랐으면서.","JPN":"どの口で下品とかいうわけ？　そんなユキは真夜中にバニーガールコスプレで走り回って海外でもニュースになったでしょ。","ENG":"Shame on you yourself. You ran around in a bunny girl suit in the middle of the night and the whole scene went viral.","TWN":"你說誰愛露？不知道是誰穿著兔女郎的衣服到處跑，結果還登上國外頭條呢？"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"아자.","JPN":"やったー。（棒読み）","ENG":"Woohoo.","TWN":"呀呵。"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"칭찬한 거 아니거든?!","JPN":"別に褒めてないけど！？","ENG":"That wasn’t a compliment!","TWN":"這不是稱讚好嗎？！"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아, 아하하……","JPN":"あ、あははは……","ENG":"Ah... Hah hah...","TWN":"喔，呵呵呵……"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"지금 실외 온도는 섭씨 38도래요. 오늘부터 전사 휴무인 태스크포스 컴퍼니도 많다네요.","JPN":"現在の外気温は38℃だそうです。今日から臨時休業のタスクフォースカンパニーも多いみたいですね。","ENG":"The outside temperature is 38 Celsius. I heard several TASKFORCE companies shut down operations today.","TWN":"聽說現在室外溫度達到攝氏38度，有很多特遣勢力公司今天開始放假呢～"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그러니까 우리 시청자 여러분들은 외출할 때는 물병 챙기고 그늘 밑으로 다니기. 미야랑 꼭꼭 약속~","JPN":"なので、視聴者の皆さんも外出する時はこまめな水分補給と、なるべく日陰を歩いてくださいね。ミヤと約束ですよ～！","ENG":"So everyone, make sure to bring water bottles with you, and stay in the shade. It’s a promise with Miya!","TWN":"觀眾們～出門在外記得要多喝水，盡量走在陽光曬不到的地方喔，打勾勾～"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"네? 나갈 일 없다고요? 하으, 그, 그런 뜻이 아니라요……","JPN":"え？　そもそもお出かけしない？　ふえぇ、そういう意味じゃなくて……","ENG":"What? You’re not going outside because you don’t have any friends? Aww... That was not what I meant...","TWN":"嗯？沒有要出門喔？欸，我的意思是……"},"stage":{"bg":"CITY_CENTER1","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그러면 더우니까 여기서 방종하고 숙소로 복귀할게요. 안녕.</color>","JPN":"<color=#ffd34c>それでは、暑いのでこの辺で配信を終了して、寮に戻りますね。バイバーイ。</color>","ENG":"<color=#ffd34c>Well, it’s too hot to go on, so we’re ending the show now. Byebye.</color>","TWN":"<color=#ffd34c>天氣太熱，今天的直播到此為止，我要回宿舍囉！掰掰～</color>"},"stage":{"bg":"SUMMER2_01_01","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"<color=#ffd34c>난 대찬성이다냥!</color>","JPN":"<color=#ffd34c>ボミも大賛成にゃ！</color>","ENG":"<color=#ffd34c>I concwur!</color>","TWN":"<color=#ffd34c>回宿舍+1喵！</color>"},"stage":{"bg":"SUMMER2_01_01","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"<color=#ffd34c>얘, 얘들아! 우리 방송 튼 지 3분도 안 지났어!</color>","JPN":"<color=#ffd34c>あ、あの！　配信を初めてまだ3分も経っていないよ！？</color>","ENG":"<color=#ffd34c>B-but guys, it’s only been three minutes!</color>","TWN":"<color=#ffd34c>大…大家，我們的直播從開始到現在，錄不到3分鐘欸！</color>"},"stage":{"bg":"SUMMER2_01_01","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"으음…….","JPN":"ううん……","ENG":"Mmm...","TWN":"嗯……"},"stage":{"bg":"SUMMER2_01_01","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이 소리는…… 넷튜브 방송인가?","JPN":"この音は……ネットチューブ配信？","ENG":"That sound... Is it NetTube?","TWN":"嗯……這是廣播的聲音嗎？"},"stage":{"bg":"SUMMER2_01_02","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이상하네……. 어제 분명 끄고 잤을 텐데…….","JPN":"おかしいな……昨日確かにおとしてから寝たはずなのに……","ENG":"That's weird... I’m sure I turned it off before I went to bed...","TWN":"奇怪……我不是關掉後才去睡的嗎……"},"stage":{"bg":"SUMMER2_01_02","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런, 소리를 조금만 키운다는 게 그만 깨워 버렸군.","JPN":"おっと、ちょっとだけ音量を上げるつもりが起こしてしまったか。","ENG":"Oops, I just wanted to turn the volume up a bit, I didn’t mean to wake you up.","TWN":"哎呀～一點點聲音就把你吵醒了嗎？"},"stage":{"bg":"SUMMER2_01_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"곤히 자는데 미안하네, 부사장.","JPN":"ぐっすり寝ていたところすまないな、副社長。","ENG":"I’m sorry, Vice President.","TWN":"吵醒你真不好意啊，副總。"},"stage":{"bg":"SUMMER2_01_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"음……? 감히 내 침실에 무단 침입해?","JPN":"は……？　私の寝室に無断侵入した命知らずがいるの？","ENG":"Huh? How dare you sneak into my bedroom.","TWN":"嗯……？你竟敢擅闖我的香閨？"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어떤 놈인지 몰라도 살아 나갈 생각은 없겠지?","JPN":"誰だか知らないが、生きて帰れると思うな！","ENG":"Whoever you are, get ready to say goodbye to your life!","TWN":"雖然我不知道你是誰，但你別想活著走出去！"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잠깐잠깐잠깐!","JPN":"待て待て待て！","ENG":"Wait, wait, wait!","TWN":"等等等等！"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나일세. 그러니까 그 리액티브 소드는 좀 내려 두고 말하게나.","JPN":"私だ。だからそのリアクティブソードはしまってくれ。","ENG":"It’s me. Please put down the Reactive Sword.","TWN":"是我啦！先把你手上的反應劍放下再說！"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……사장님?","JPN":"……社長？","ENG":"Boss?","TWN":"……老闆？"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무슨 일이시죠? 분명 오늘부터 전사 휴무니 푹 쉬고 오라고 하셨을 텐데요?","JPN":"どうしましたか？　確か今日は全社休業だからゆっくり休んでこいと聞いたはずですが。","ENG":"What are you doing here? You told me that we’re all off work today.","TWN":"有什麼事嗎？不是你自己說從今天開始全公司放假嗎？"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아침에 약한 자네의 귀여운 코맹맹이 소리를 듣고 싶어져서 말이야.","JPN":"朝に弱い君の可愛い鼻声が無性に聞きたくなってな。","ENG":"I just wanted to hear your twang.","TWN":"就早上突然有點想念你可愛的打呼聲嘛～"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"죽고 싶다는 말을 이상하게 돌려서 하시는군요.","JPN":"それはあの世に逝きたいという意思表明の新しい言い回しですね。","ENG":"Was that your death wish?","TWN":"你以為加上可愛我就不會打死你嗎？"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쨌든 알겠습니다. 충성스런 부하직원으로서 기꺼이 그 길고 한심한 인생을 끝내드리죠.","JPN":"とにかくわかりました。忠誠心が高い部下として、喜んでその長きに渡る情けない人生を終わらせてあげましょう。","ENG":"I understand. As your loyal employee, I will gladly end your long and pathetic life.","TWN":"沒問題！身為一位忠心的職員，既然老闆這麼想死，我只好恭敬不如從命！"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"농담일세, 농담! 그 칼 좀 저리 치우게나!","JPN":"冗談だ、冗談！　だからその剣をしまってくれ！","ENG":"That was a joke! A joke! Please put away that sword!","TWN":"開玩笑的啦～沒事沒事！快把刀放下！"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"실은 어제 전사 휴무를 공지한 뒤에 하나 양이 그러더군.","JPN":"実は昨日、全社休業を告知した後に管理部長からある話を聞いてな。","ENG":"Yesterday, Hana told me something after the day-off announcement.","TWN":"事情是這樣的，昨天宣布全公司放假後，荷娜跟我說…"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"후후, 전사 휴무는 오랜만이네요.","JPN":"フフ、全社休業は久しぶりですね。","ENG":"Oh, it’s been a while since the whole company got a day off.","TWN":"哇～好久沒有全公司放假囉？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음? 작년에는 전사 휴무를 안 했나?","JPN":"うん？　去年は全社休業がなかったのか？","ENG":"Hm? There was no day-off last year?","TWN":"是嗎？公司去年沒放嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그라운드 원은 대균열 때문에 이상 기후가 심해서 도시관리국도 권장하고 있을 텐데?","JPN":"グラウンド・ワンは大亀裂のせいで異常気象が激しいから、都市管理局も推奨していたはずなんだが。","ENG":"City Management recommends companies to have day-offs, as Ground One suffers several weather anomalies due to the Grand Dimension Crevice.","TWN":"G1因為大峽谷的關係導致氣候嚴重異常，城市管理局應該也有建議要放假吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"다 같이 며칠씩이나 쉴 만큼 회사 형편이 여유롭진 않았으니까요.","JPN":"全員で数日休めるほど、会社の財政事情に余裕がありませんでしたので。","ENG":"Well, we didn’t have the luxury of taking holidays back then.","TWN":"因為公司的財務狀況，沒辦法讓全公司員工放那麼多天假。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"특히 부사장님께서 고생하셨죠. 몇 년간 휴가 한 번 없이 주말에도 나와서 일하셨거든요.","JPN":"特に副社長がかなり苦労されてましたね。数年間ずっと休みを返上して週末も働いているんです。","ENG":"Especially the Vice President. She worked 24/7 for years without a single vacation.","TWN":"尤其是副總超辛苦的！她已經好幾年沒休假，連假日也要辦公。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"호오…….","JPN":"……ほう。","ENG":"Ooh...","TWN":"喔嗚……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……하나 씨도 참, 은근히 입이 가볍다니까요.","JPN":"ナカシマさんったら……意外と口が軽いんですね。","ENG":"... Hana sometimes talks too much.","TWN":".荷娜也真是的，沒想到是個大嘴巴。"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 그래서 자네가 모처럼의 휴가를 근사하게 보내도록 도와 주러 온 걸세.","JPN":"まあ、ということで君がせっかくの休みを優雅に過ごせるように手伝いに来たわけさ。","ENG":"Well, I’m here to help you to enjoy your first vacation in years.","TWN":"嗯，所以我是來幫助你過個難忘的假期的。"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구체적인 조건을 말씀해 주시면 검토해 보기로 하죠.","JPN":"具体的な条件を教えてくれたら、検討します。","ENG":"Give me the specifics then I’ll go through them.","TWN":"可以告訴我具體的內容，我會考慮看看。"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"거래에 임할 생각은 있다는 뜻으로 이해되는군.","JPN":"取引に応じる可能性はあると受け止めていいんだな。","ENG":"I see you’re ready to make a deal.","TWN":"這表示你同意我的提議吧？"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"백 번 듣는 것보단 한 번 경험하는 게 낫지. 어서 나갈 준비 하게나.","JPN":"百聞は一見に如かず、一度経験したほうがいいだろう。さっそく出かける準備をしよう。","ENG":"Actions speak louder than words. Let’s get ready to go outside.","TWN":"百聞不如一見，趕快準備出門吧。"},"stage":{"bg":"SUMMER2_01_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh*","TWN":"哎…"},"stage":{"bg":"SUMMER2_01_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 왜 그러나?","JPN":"うむ？　どうしたのかね？","ENG":"Hm? What’s wrong?","TWN":"嗯？你怎麼了？"},"stage":{"bg":"SUMMER2_01_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제가 잠잘 때 옷 입기 싫어한다는 거, 잘 아시지 않습니까?","JPN":"私が寝る時は服を着ないことは、よくご存知でしょう。","ENG":"You know I don’t wear clothes when I go to bed.","TWN":"你應該知道我睡覺的時候習慣裸睡吧？"},"stage":{"bg":"SUMMER2_01_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하. 알 만큼 아는 사이끼리 새삼스럽게…….","JPN":"ハハハ、もちろんさ。何を今更……","ENG":"Hah hah, I thought we were close enough to...","TWN":"哈哈，大家都這麼熟了，跟我客氣什麼…"},"stage":{"bg":"SUMMER2_01_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당장 나가요!","JPN":"今すぐ出て行ってください！","ENG":"Get out!","TWN":"馬上給我出去！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……베개도 자네가 던지니 좀 아프군.","JPN":"……君が投げる枕はすごい威力だな。","ENG":"Even a pillow hurts when you throw it.","TWN":"…被你扔的枕頭打到還真的有點疼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래서, 어디로 데려갈 생각이시죠?","JPN":"それで、どこに連れていくつもりですか？","ENG":"So, where are you taking me?","TWN":"所以，你要帶我去哪裡？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"호텔 아르마다로. 옥상에 있는 수영장이 경치가 무척 좋다더군.","JPN":"ホテルアルマダへ。屋上のプールからの景色が格別だそうだ。","ENG":"To Hotel Armada. I heard their rooftop pool has a wonderful view.","TWN":"帶你去艾魯瑪達飯店。聽說頂樓的泳池景色超棒喔！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아르마다라면……. 확실히 며칠 전에 만난 거래처 대표도 무척 호평하더군요.","JPN":"アルマダなら……確かに数日前に会った取引先の社長も評価していましたね。","ENG":"Armada... One of our client’s CEO spoke highly of the place a few days ago.","TWN":"艾魯瑪達嗎… 前幾天見到的客戶代表好像也滿喜歡的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런데 거길 언제 예약하셨습니까? 예약 일정은 내년까지 전부 차 있을 텐데요?","JPN":"ところで、いつ予約したのですか？　あのホテルの予約は来年まで埋まっているはずですが。","ENG":"But how? I heard the hotel was fully booked until next year.","TWN":"不過你什麼時候預訂的？飯店的預約應該到明年都滿了吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"에헴. 고생하는 부사장을 위해 내가 그 정도도 못 해 주겠나.","JPN":"えっへん。苦労している副社長のために、それぐらいできて当然だ。","ENG":"Ahem... I can do anything for my dear hard-working Vice President.","TWN":"呵呵，為了辛苦工作的副總，區區小事不足掛齒。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"실은 자네를 위해 그라운드 원의 기상조절 시스템을 살짝 손봐 놓았다네.","JPN":"実は君のために、グラウンド・ワンの気象調整システムにちょっとだけ手を加えたのさ。","ENG":"To tell you the truth, I even tweaked the Ground One Weather Control System a bit for you.","TWN":"其實我爲了你，還稍微動了G1 的氣象調節系統呢。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자, 가지. 좀 덥긴 해도 오늘은 이 도시 역사상 물놀이를 하기 가장 적합한 날씨가 될 거야.","JPN":"さあ、出発しよう。少し暑いが、今日はこの都市史上最高に水遊びにピッタリな天気になるはずさ。","ENG":"Let’s go. It’s a bit hot, but today will be the best day to go swimming.","TWN":"我們走吧！雖然有點熱，但今天會是這個城市史上最適合玩水的天氣喔！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>속보입니다. 기상조절 시스템의 오작동으로, 현재 그라운드 원의 기온은 섭씨 45도를 웃돌고 있습니다.</color>","JPN":"<color=#ffd34c>速報です。気象調節システムの誤作動で、現在グラウンド・ワンの気温は45℃を超えています。</color>","ENG":"<color=#ffd34c>This just in. Due to the Weather Control System malfunction, the current temperature of Ground One has now reached 45 Celsius.</color>","TWN":"<color=#ffd34c>快報！由於氣象調節系統故障，現在 G1 的氣溫已經超過攝氏45度。</color>"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L44_1","type":"dialog","speaker":"TV1_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>현장에 나간 기자를 통해 더 자세한 소식 전해 드리겠습니다.</color>","JPN":"<color=#ffd34c>現場のリポーターに繋げて、より詳しくお伝えします。</color>","ENG":"<color=#ffd34c>More news from the scene.</color>","TWN":"<color=#ffd34c>請特派記者為我們帶來現場消息。</color>"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TV2_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>여기는 도시 관리국 앞입니다! 바깥 날씨는 보시는 것처럼 도로에 놔둔 베이컨이 바짝 익을 정도로……!</color>","JPN":"<color=#ffd34c>こちらは都市管理局の前です！　外の空気はご覧のとおり、道路に乗せたベーコンがカリカリに焼けるぐらいです……！</color>","ENG":"<color=#ffd34c>I’m here right in front of City Management! As you can see, I put a piece of bacon on the road, and it fries instantly...</color>","TWN":"<color=#ffd34c>這裡是城市管理局前門！如大家所見，外面的天氣熱到可以煎雞蛋………！</color>"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"말씀하신 대로 <color=#ffd34c>좀</color> 덥군요. 수영장에 들어갔다간 산 채로 삶아질 정도로요.","JPN":"おっしゃるとおり<color=#ffd34c>少し</color>暑いですね。プールに入ると生きたまま茹でられるんじゃないかと思うぐらいです。","ENG":"Like you said, it’s <color=#ffd34c>a bit</color> hot here. Hot enough to boil in a pool.","TWN":"就像你說的是<color=#ffd34c>有點</color> 熱，跳進泳池應該會被煮熟吧？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 기상조절 시스템에 무슨 짓을 하신 거죠?","JPN":"気象調節システムに何をしたのですか？","ENG":"What have you done to the Weather Control System?","TWN":"你到底對氣象調節系統做了什麼？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하. 하하. 하.","JPN":"アハハ。ハハハ。","ENG":"Hah. Hah hah... Hah.","TWN":"哈，哈哈，哈。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이, 이럴 리가 없는데…….","JPN":"こ、こんなはずがない……","ENG":"Th-this shouldn't be happening...","TWN":"怎… 怎麼會這樣… "},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"걱정 말게나! 아르마다는 세계 최고의 호텔 브랜드야!","JPN":"心配することはない！　アルマダは世界最高のホテルブランドだ！","ENG":"Don’t worry! Armada is the best hotel in the world!","TWN":"請不要擔心！艾魯瑪達是全世界最好的飯店品牌！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"겨우 폭염 따위로 수영장 수온 관리를 실패할 리가……","JPN":"たかが猛暑ぐらいで、プールの水温管理に失敗するはずが……","ENG":"I’m sure they can control their pool’s water temperature...","TWN":"不可能因為酷暑而導致游泳池水溫管理失敗…"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아, 네. 전화 받았습니다. 누구시죠?","JPN":"はい、もしもし。","ENG":"Hello?","TWN":"啊，喂，請問是誰？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L10_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"갑자기 연락 드려 죄송합니다, 손님.","JPN":"急な連絡で申し訳ございません、お客様。","ENG":"Hello, this is Hotel Armada.","TWN":"客人不好意思，突然打給您。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"실은 방금 전, 차원 함선이 저희 호텔 옥상을 들이받아 모시기 어렵게 되었습니다.","JPN":"実は先ほど、次元艦船が当ホテルの屋上に衝突し、お迎えすることが難しくなりました。","ENG":"As a dimensional ship has crashed on our rooftop, we won’t be in service today. My apologies.","TWN":"是這樣的，剛才有一艘次元艦船撞到我們飯店的屋頂，恐怕無法再繼續接待您。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"뭐시라?! 함선이 들이받아?!","JPN":"なんだと！？　艦船が衝突！？","ENG":"What?! A dimensional ship crashed your building?!","TWN":"什麼？被艦船撞到？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L14_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"네. 사고 경위를 파악 중인 조사관에 따르면 일사병으로 인한 오퍼레이터의 조종 실수가 유력하다고 합니다.","JPN":"はい。事故の経緯を把握している調査官によると、熱中症によるオペレーターの操縦ミスが原因だそうです。","ENG":"Yes. The investigator says it’s highly likely that the operator suffered heat stroke and lost control...","TWN":"是的。正在調查意外經過的調查人員表示，很可能是因為領航員中暑，導致操作失誤。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"후속 조치에 대해서는…….","JPN":"今後の対応に関しましては……","ENG":"Regarding the follow up measures...","TWN":"有關後續處理…"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"혹시 이거 몰래 카메라입니까? 마지막엔 스승님이 미안하다면서 도망치고 끝나나요?","JPN":"もしかしてドッキリですか？　最後は師匠がすまないと言って、逃げるのがオチですかね？","ENG":"Boss, is this a candid camera? Does this show end with the Master running away saying she’s sorry?","TWN":"這是惡作劇嗎？等一下師父該不會突然出現，然後說句對不起就跑掉？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠, 흠! 사고야 언제 어디서든 일어날 수 있지!","JPN":"こ、こほん！　事故はいつどこにでもあり得ることだ！","ENG":"Ahem! Hmm! Accidents can happen!","TWN":"咳咳，嗯！意外本來就是無法預期的嘛！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하지만 걱정 말게. 내가 누군가.","JPN":"しかし心配するな。私が誰なのか知っているだろ。","ENG":"But don’t worry. You know me.","TWN":"不過你不要擔心！就相信我吧！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이런 일이 있을 줄 알고 자네의 휴가 계획을 플랜 A부터 AXZ까지 마련해 뒀다네!","JPN":"こんなこともあろうかと思って、君の夏休み計画はプランAからAXZまで用意しているのさ！","ENG":"I knew something like this was going to happen, so I planned everything from A to AXZ!","TWN":"我早就知道會發生這樣的事，你的假期安排，我從A計畫到Z計畫都已經準備妥當！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"네?! 사장님, 코핀 함은 전사 휴무라 정기 수리 보내 뒀는데요?!","JPN":"え！？　社長、コフィン艦は全社休業で定期修理に出していますよ！？","ENG":"Huh?! But Boss, Coffin was sent for repair as today is a day-off!","TWN":"嗯？！老闆，科芬公司因為全公司放假，就把科芬艦送到這來定期維護咧？！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"아?! 스톱! 거기 아저씨 스톱! 제 선풍기라고요, 그거!","JPN":"あっ！？　ストップストップ！　それは私の扇風機なのです！","ENG":"Oh?! Stop, hey, stop! That’s my fan!","TWN":"哦？！停！那邊的叔叔停下！那是我的電風扇啦！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"사장님, 격납고에 에어컨 좀 더 달아 주시면 안 될까요? 정비원 분들이 자꾸 떼어 가서요!","JPN":"社長、格納庫にエアコンを増やしてくれませんか？　整備士たちが勝手に持っていっちゃうのです。","ENG":"Boss, could you get us more air-conditioners in the Hangar? The mechanics are constantly taking away the air-cons!","TWN":"老闆，能不能在機庫裡再多裝幾台冷氣？維修人員老是把冷氣拆走！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네. 그라운드 원을 떠나는 항공편은 현재 급성 침식 현상 때문에 전부 결항 상태입니다.","JPN":"はい。グラウンド・ワンを発つ航空便は、現在急性侵食現象により全て欠航状態です。","ENG":"Yes, all flights heading out from Ground One are suspended due to the acute Counterside Effect.","TWN":"是的。離開 G1 的航班，目前因緊急侵蝕現象全部停飛。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"여객선들도 이상기후로 발생한 태풍 탓에 오늘 내로 출항하긴 어렵다고 하네요.","JPN":"旅客船も異常気象で発生した台風のせいで、今日中に出航するのは難しいそうです。","ENG":"Also, passenger ships won’t be leaving the city today because of the storm.","TWN":"據說客輪也因氣候異常而發生的颱風，今天看來是很難出航。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그리고 비상 대기 중인 힐데 소대장님이 사장님께 긴히 할 얘기가 있으시다고───","JPN":"そして非常待機中のヒルデ小隊長が社長に大事なことがあると───","ENG":"Commander Hilde is on emergency stand-by, and wants to talk to you—","TWN":"另外，緊急待命中的希爾德隊長說有急事找老闆───"},"stage":{"bg":"OFFICE","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"네에…… 모의전 시뮬레이션은 지금 긴급 점검 중입니다……","JPN":"はあ……模擬戦シミュレーションはただいま緊急メンテナンスなんです……","ENG":"Yes... Simulation is currently under emergency maintenance...","TWN":"是. 模擬戰模擬器目前緊急維護中…"},"stage":{"bg":"LABORATORY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"직원 분들이 요즘 자주 사용하셔서요, 네…… 휴양지는 구현하기 어렵다네요……","JPN":"社員の方が最近よく使っているので、はい……リゾート地は再現するのが難しいようです……","ENG":"The employees have been using it often lately... Yes, it’s hard to render a resort...","TWN":"因為最近員工使用太頻繁，是…度假村可能做不出來… "},"stage":{"bg":"LABORATORY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"……오늘부터 전사 휴무요? 새로 나온 논문 이름인가요?","JPN":"……今日から全社休業ですか？　それって新しい論文の名前ですか？","ENG":"... Company day-off? Is that a new thesis title?","TWN":"…全公司從今天開始放假？這是新出刊的論文題目嗎？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"플랜 A부터 AXZ까지 전부 실패로군요. 훌륭합니다.","JPN":"プランAからAXZまで全部失敗ですね。お見事です。","ENG":"So, everything from A to AXZ is a failure. Great.","TWN":"計畫A到Z計畫全部失敗了，真是好棒棒！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"말도 안 돼! 설마 마왕 중의 누군가가 꾸민 계략인가!","JPN":"ありえない！　まさか魔王の誰かが企んだ計略か？","ENG":"This can’t be! Maybe it’s a Demon Lord’s doing!","TWN":"太誇張了吧！是哪個魔王在弄我嗎？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"기껏 수영복까지 사 왔는데 이럴 수는 없어!","JPN":"せっかく水着まで買ってきたのに！","ENG":"I even brought you a swimsuit!","TWN":"我還特地買了泳衣，我不會放棄的！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대로에서 큰소리로 말씀하지 마시죠. 부끄러우니까요.","JPN":"道端で大声で叫ぶのはおやめください。こっちが恥ずかしいです。","ENG":"Stop yelling in the middle of the street. You’re embarrassing me.","TWN":"大庭廣眾之下不要大聲嚷嚷，很丟人。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무튼, 전 결국 집에서 휴가를 보내야 할 운명 같군요.","JPN":"私は結局、家で休む運命だったようですね。","ENG":"Anyway, I guess I’m destined to spend the day-off at home.","TWN":"總之，我命中註定要在家度假。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님도 이 더위에 돌아다니지 마시고 얌전히 집에서 쉬시죠.","JPN":"社長もこの暑さで外にいるのは危ないですし、大人しく自宅で休んでください。","ENG":"Boss, you should go home too. It’s too hot to stay outside.","TWN":"天氣這麼熱，老闆也別亂跑，乖乖待在家休息吧。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시관리국에서 안내드립니다. 현재 이 방송이 들리는 주거 구역은 대규모 정전 사태가 발생한 상황입니다.</color>","JPN":"<color=#ffd34c>都市管理局からご案内します。現在、この放送が流れる住居区域に大規模停電が発生しています。</color>","ENG":"<color=#ffd34c>This is an announcement from City Management. If you’re hearing this, it means you’re in a residential zone with a large-scale blackout.</color>","TWN":"<color=#ffd34c>城市管理局通知，現在收聽得到這個廣播的地區發生大規模停電。</color>"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시민 여러분은 전력 공급이 복구되기 전까지 그늘진 곳에서 기다려 주시고…….</color>","JPN":"<color=#ffd34c>市民の皆さんは電力供給が復旧されるまで、日陰でお待ちいただくよう……</color>","ENG":"<color=#ffd34c>Please hold on until the power is restored. Stay in the shade...</color>","TWN":"<color=#ffd34c>請市民們在恢復供電之前，在陰涼處等待………</color>"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"귀가하기 전에 발전소 담당자를 추궁하러 가야겠군요.","JPN":"帰宅する前に発電所の担当者を追及しに行かなければなりませんね。","ENG":"I think I’ll go and question the plant operator before I go home.","TWN":"看來回家前必須先去向發電廠的負責人究責。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"회사에서 제 장비를 가져 와야겠습니다. 비상 사태니 상관없겠죠?","JPN":"会社から私の装備を持って来ます。非常事態ですから問題ないでしょう？","ENG":"First, I need my gear from the company. It’s an emergency, so it’s okay, right?","TWN":"我要去公司拿我的裝備，現在是緊急狀況，應該沒關係吧？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"기다리게, 부사장! 도시관리국이랑 싸워서 어쩌려고!","JPN":"待ってくれ、副社長！　都市管理局と戦ってどうするんだ！","ENG":"Halt, Vice President! Why would you fight the City Management?","TWN":"副總請留步！和城市管理局吵架有什麼用！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자, 마지막 비장의 수단이 남아 있어. 이 방법이라면 확실할 걸세.","JPN":"まあ、最後の切り札が残っている。この方法なら間違いないだろう。","ENG":"Look, I still have a card up my sleeve. I’m sure it will work.","TWN":"好吧！我還有最後的必殺技，這個方法肯定OK！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이건…… 플로라 메이드 서비스의 전단지 아닙니까?","JPN":"これは……フローラメイドサービスのチラシ？","ENG":"This is... Flora Maid Service's ad flyer.","TWN":"這…是芙蘿拉女僕服務公司的傳單吧？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"역시 자네야. 이 초현실주의 미술 작품을 단번에 알아보는군.","JPN":"さすが君だ。この超現実主義の美術品にすぐ気付くとは。","ENG":"I knew it. I knew you would recognize this surrealist artwork.","TWN":"不愧是副總！一眼就認出這幅超現實主義的美術作品！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"연락해 주시기를 기다리고 있었습니다. 주인님.","JPN":"ご連絡をお待ちしておりました、ご主人様。","ENG":"I was waiting for your call, Master.","TWN":"我一直在等候您來電呢，主人。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"메이드장 베로니카, 인사드립니다. 그간 무탈하게 지내셨는지요.","JPN":"メイド長ベロニカ、ご挨拶申し上げます。お変わりございませんか。","ENG":"Chief Maid Veronica, at your service. I hope you fared well.","TWN":"女僕長 貝洛妮卡向您問安，別來無恙。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오오. 오랜만일세, 베로니카 양.","JPN":"ああ、久々だな。ベロニカ。","ENG":"Oh, it’s been a while, Veronica.","TWN":"喔喔～好久不見了，貝洛妮卡。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"우린 지금 중대한 난관에 봉착했다네. 자네 힘이 필요한 순간이야.","JPN":"我々は今重大な困難に直面している。君の力が必要な時が来た。","ENG":"We’re currently in big trouble. We really need your help.","TWN":"我們現在面臨到重大難題，正是需要你的時候！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님께서 원하신다면 얼마든지 도와드리겠습니다. 어떤 고민이신지요.","JPN":"ご主人様のお望みならば、何なりとお申し付けください。どのようなお悩みでしょうか。","ENG":"As you wish, Master. What is it that you want?","TWN":"只要主人一句話，我都會盡我所能地協助，請問是什麼難題呢？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"요약하면 부사장님께서 만족하실 만한 휴양지로 찾고 계신다는 말씀이시군요.","JPN":"要するに、副社長が満足できそうなリゾート地をお探しということですね。","ENG":"So to summarize, you’re looking for a good vacation spot for the Vice President.","TWN":"簡單來說，就是您正在尋找副總會滿意的度假村對吧？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"미안하네. 지구 반대편에 있는 자네한테 어려운 부탁인 줄은 아네만…….","JPN":"すまない。今地球の反対側にいる君に難しい依頼であるのは承知の上だが……","ENG":"I’m sorry. I know it’s a difficult task, considering that you’re on the other side of the Earth and all...","TWN":"很抱歉，我知道這個請求，對於身處地球另一端的你來說有點為難……"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그 말씀은 부디 거두어 주시길. 주인님께 보탬이 되는 것은 메이드의 보람입니다.","JPN":"滅相もないことでございます。ご主人様のお役に立つことこそ、メイドの喜びです。","ENG":"Please refrain from such comments. It’s a maid’s honor to help her master.","TWN":"請不要這麼說，能為主人做事是我的榮幸。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"마침 메이드 일을 하면서 교류하게 된 분이 계시답니다.","JPN":"ちょうどメイドの仕事中に出会い、交流している方がいます。","ENG":"I happen to know this one person from my maid business.","TWN":"剛好我有在工作中認識一個人。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그분이라면 분명 두 분을 만족스러운 휴양지로 안내해 주실 겁니다.","JPN":"その方なら、お二人のお気に召されるリゾート地へ案内できると思います。","ENG":"I’m sure she will lead you two to a vacation spot to your satisfaction.","TWN":"她應該可以介紹讓兩位都滿意的度假村。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"지금 계신 곳을 알려 주시죠. 바로 연락하도록 하겠습니다.","JPN":"今いらっしゃる場所を教えてください。ただちに連絡を入れるよう手配いたします。","ENG":"Please tell me where you are now. I’ll make the call right away.","TWN":"請告訴我您現在的位置，我會馬上跟您聯絡。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확실히 훌륭한 인재로군요.","JPN":"確かに素晴らしい人材ですね。","ENG":"She really is a special talent.","TWN":"果然是很優秀。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"세계를 수도 없이 말아먹은 누구와는 다르게 말이죠.","JPN":"世界を何度も崩壊させた誰かさんと違って。","ENG":"Unlike someone who almost destroyed the world countless times.","TWN":"和老是惹麻煩的傢伙就是不一樣。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠흠…….","JPN":"こ、こほん……","ENG":"Ahem...","TWN":"咳嗯嗯…"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면 맨션 사건 때 어떻게든 정규직으로 고용해 둘 걸 그랬습니다.","JPN":"こうなると分かっていたら、マンション事件の時に何としてでも正社員として雇っておけばよかったです。","ENG":"I should have hired her as a regular employee after the Mansion incident.","TWN":"早知如此，在曼森事件時，不管怎麼樣都要聘請她為正式員工才對。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하, 급할수록 돌아가란 말도 있지 않나.","JPN":"ハハハ、急がば回れという言葉もあるじゃないか。","ENG":"Hah hah, there’s a saying, “Make haste slowly.”","TWN":"哈哈，俗話不是說「吃緊弄破碗」嗎？ "},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"베로니카 양에게도 마음 정리할 시간이……","JPN":"ベロニカにも心を整理する時間が……","ENG":"Veronica also needs some time to get herself sorted...","TWN":"應該要給貝洛妮卡一些思考的時間…"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":" 응?","JPN":"うん？","ENG":" Huh?","TWN":"嗯？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L37_1","type":"dialog","speaker":"LARA_NPC_DILIVER_NULL","text":{"KOREA":"비켜! 비켜비켜비켜비켜비켜비켜비켜비켜!!!","JPN":"どいてー！　どいてどいてどいてどいてどいてどいてどいてどいてー！！","ENG":"Out of my way! Move! Move! Move!","TWN":"讓開！讓開讓開讓開讓開讓開讓開！！！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"괜찮으십니까, 사장님?","JPN":"大丈夫ですか？　社長！","ENG":"Are you okay, Boss?","TWN":"老闆你沒事吧？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그, 그럼. 자네가 막아 준 덕분일세.","JPN":"な、なんとか。君が防いでくれたおかげだ。","ENG":"S-sure, all thanks to you.","TWN":"當…當然，幸好有你擋著。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그리고 나보다는 자네랑 부딪쳐서 튕겨 나간 저 아가씨부터 걱정해야 할 것 같군.","JPN":"ところで、私よりも君にぶつかって弾き飛ばされたあの女性を心配したほうがよさそうだ。","ENG":"I think you should worry about that girl, rather than me.","TWN":"而且我覺得那位撞到你後彈飛出去的小姐，好像更需要關心。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"LARA_NPC_DILIVER_NULL","text":{"KOREA":"아구구구……","JPN":"いててて……","ENG":"Argh...","TWN":"哎唷喂呀…"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_DILIVER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LARA_NPC_DILIVER_NULL","text":{"KOREA":"죄송합니다! 목적지까지 서두르는 바람에 하마터면 다치게 할 뻔했네요!","JPN":"すみません！　あまりにも急いだせいで、危うく怪我をさせてしまうところでした！","ENG":"My apologies! I was in such a hurry, I almost hurt you!","TWN":"對不起！急著要趕到目的地差點害你受傷。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_DILIVER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"전 플라티나 익스프레스의 라라 예거예요! 배달부죠!","JPN":"私はプラチナエクスプレスのララ・イェーガーです！　配達員です！","ENG":"I’m Lara Jaeger from Platina Express! I’m a deliverywoman!","TWN":"我是白金運通的拉拉·伊格，是個送貨員！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"이건 제 명함! 그럼 전 제 도움이 필요하다는 분이 계셔서 이만!","JPN":"これは私の名刺です！ では、自分の助けを必要としている方がいらっしゃるので、これで失礼します！","ENG":"This is my business card! There’s someone waiting for me, so I’ll be going now!","TWN":"這是我的名片！還有人在等我，先告辭囉！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아, 잠시만 기다리게.","JPN":"あっ、待ってくれ。","ENG":"Wait a minute.","TWN":"喂，先別走。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"넹?","JPN":"はいっ？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"혹시 자네가 베로니카 양이 말한 사람인가? 우릴 휴양지로 데려다 준다던?","JPN":"もしかして君がベロニカが言っていた人か？　私たちをリゾート地まで連れてくれると聞いたが。","ENG":"Are you the one Veronica told me about? The one who’s supposed to take us to the vacation spot?","TWN":"你是貝洛妮卡說的那個人嗎？你會帶我們到度假村？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗, 베로니카 씨랑 아는 사이셨어요?","JPN":"お、ベロニカさんのお知り合いだったんですね！","ENG":"Oh, you know Veronica?","TWN":"咦，你認識貝洛妮卡嗎？"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"정말 너무 좋은 분인 거 있죠? 제가 원래 24시간 가만히 있는 날이 없다 보니까 방 청소도 못하고 살았는데 때마침 그때!","JPN":"本当にいい方ですよね！　私ってあまり24時間部屋でゆっくりできる日がないからずっと部屋の掃除もまともにできなくて困っていた時があったんですけど、ちょうどタイミングよく！","ENG":"She’s such a good person! You see, I’m always on my way to deliver something, and I barely have any time to clean up my room. But then!","TWN":"她真的很棒對吧！我每天都忙於工作，根本沒時間打掃，但就在那個時候！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스의 전단지를 발견하고 연락을 드렸더니 하루만에 말끔히 치워 주시더라고요!","JPN":"フローラメイドサービスのチラシをみて連絡したら1日でキレイに片付けてくれました。","ENG":"I found a Flora Maid Service flyer and called, and she cleaned up my room in just a single day!","TWN":"發現芙蘿拉女僕服務公司傳單，就嘗試聯繫一下，沒想到不到一天就幫我打掃得乾乾淨淨！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"물론 며칠 못 가서 다시 어지럽히긴 했지만요.","JPN":"もちろん数日経たずでまた散らかってしまいましたが……","ENG":"Well, the room got messy again after a few days though.","TWN":"當然才過沒幾天就又被我弄亂了。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"그래도 진짜 깔끔하게 잘 정리해 주셔서 꼭 새로 입주한 집 같았는데 제가 지금처럼 워낙 정신없는 성격이라 눈 깜짝할 새 세상에 맙소사 난장판이 되는 거 있죠?","JPN":"でも本当にキレイに片付けまでしてくれたおかげでまるで新居のようになったんですが私ってさっきみたいにあまりにも落ち着きがない性格なのであっという間にめちゃくちゃになっちゃうんです。","ENG":"But still, when she cleaned up my room it was good as new, but I’m such a messy girl and oh my God my room went crazy like that in the blink of an eye!","TWN":"不過她真的幫我整理得很乾淨，乾淨到就像搬進新家一樣。看也知道我這個人神經很大條，所以房子瞬間就變成亂七八糟囉。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"흑흑. 그래서 베로니카 씨한테 싹싹 빌면서 한 번만 더 치워 줄 수 있냐고 부탁했더니 기꺼이 도와 주시더라고요.","JPN":"ぐすん。だからベロニカさんに正座してもう一度片付けてほしいとお願いしたら快く助けてくれました。","ENG":"*Sob* So I begged Veronica to clean up my room just one more time, and she helped me again.","TWN":"嗚嗚，後來我就哀求貝洛妮卡再幫我打掃一次，她竟然欣然答應欸。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"그 때 바로 촉이 팍 하고 꽂혔죠! 아, 이 사람은 믿을 수 있는 사람이다! 은혜를 원수로 갚지 말아야지!","JPN":"あの時ピンと来たのです！　あ、この人は信用できる人だと！　恩を仇で返すことはしない！","ENG":"That’s when I realized that she’s a trustworthy person and I simply must repay her kindness!","TWN":"那個時候就心想，這個人信得過！我一定要向她報恩！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"그렇게 굳게 다짐을 했다는 거 아니겠어요. 제가 워낙 배달을 여기저기 다니다 보니 사람 보는 눈은 좀 있다고 생각하는데요, 그렇다고 꼭 백발백중 들어맞는다는 뜻은 아닌데","JPN":"そうやって固く決心したわけです。私って仕事であちこち回っているから人を見る目は多少はある方だと思います。だからといって必ずしも百発百中当てはまるというわけではありませんが。","ENG":"That was my resolution. You see, I’ve been running around delivering goods, meeting a lot of people, and I know a good person when I see one, though that’s not a hundred percent guaranteed.","TWN":"任誰都會這麼想的嘛！我做外送這行看過的人也不少，還算是有點看人的眼光，當然也不是每次都很準啦。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};